// Availability Set with 3 fault domains and 5 update domains
resource availabilitySet 'Microsoft.Compute/availabilitySets@2023-03-01' = {
  name: 'myAvailabilitySet'
  location: location
  sku: {
    name: 'Aligned'   // Required for managed disks
  }
  properties: {
    platformFaultDomainCount: 3
    platformUpdateDomainCount: 5
  }
}

// VM referencing the Availability Set
resource vm1 'Microsoft.Compute/virtualMachines@2023-03-01' = {
  name: 'myVM-1'
  location: location
  properties: {
    availabilitySet: {
      id: availabilitySet.id
    }
    hardwareProfile: { vmSize: 'Standard_DS2_v2' }
    storageProfile: {
      imageReference: {
        publisher: 'Canonical'
        offer: 'UbuntuServer'
        sku: '22_04-lts'
        version: 'latest'
      }
      osDisk: {
        createOption: 'FromImage'
        managedDisk: { storageAccountType: 'Premium_LRS' }
      }
    }
    // ... osProfile, networkProfile ...
  }
}

resource "azurerm_availability_set" "example" {
  name                         = "myAvailabilitySet"
  resource_group_name          = azurerm_resource_group.example.name
  location                     = azurerm_resource_group.example.location
  platform_fault_domain_count  = 3
  platform_update_domain_count = 5
  managed                      = true   # Required for managed disk alignment
}

resource "azurerm_linux_virtual_machine" "vm1" {
  name                = "myVM-1"
  resource_group_name = azurerm_resource_group.example.name
  location            = azurerm_resource_group.example.location
  size                = "Standard_DS2_v2"
  availability_set_id = azurerm_availability_set.example.id   # Reference the AS

  admin_username = "azureuser"
  admin_ssh_key {
    username   = "azureuser"
    public_key = file("~/.ssh/id_rsa.pub")
  }

  network_interface_ids = [azurerm_network_interface.vm1.id]

  os_disk {
    caching              = "ReadWrite"
    storage_account_type = "Premium_LRS"
  }

  source_image_reference {
    publisher = "Canonical"
    offer     = "UbuntuServer"
    sku       = "22_04-lts"
    version   = "latest"
  }
}
